// Determine which reminders are due right now
// Runs every hour; checks if any reminder's cron matches this hour/minute
const now = new Date();
const currentHour = now.getUTCHours();
const currentMinute = now.getUTCMinutes();
const currentDayOfWeek = now.getUTCDay(); // 0=Sun, 1=Mon, ...

const remindersRaw = $('Read Reminder Schedule').item.json;
const registryRaw = $('Read Feature Registry').item.json;

const scheduleData = typeof remindersRaw === 'string' ? JSON.parse(remindersRaw) : remindersRaw;
const registry = typeof registryRaw === 'string' ? JSON.parse(registryRaw) : registryRaw;

const enabledFeatureIds = new Set(
  (registry.features || []).filter(f => f.enabled).map(f => f.id)
);

// Parse cron expression: "minute hour day-of-month month day-of-week"
function cronMatches(cronExpr, hour, minute, dayOfWeek) {
  const parts = cronExpr.split(' ');
  if (parts.length < 5) return false;

  const [cronMin, cronHour, , , cronDow] = parts;

  const hourMatch = cronHour === '*' || parseInt(cronHour) === hour;
  const minMatch = cronMin === '*' || parseInt(cronMin) === minute;
  const dowMatch = cronDow === '*' || parseInt(cronDow) === dayOfWeek;

  return hourMatch && minMatch && dowMatch;
}

const dueReminders = (scheduleData.reminders || []).filter(r => {
  if (!r.enabled) return false;
  // Skip feature-specific reminders if the feature is disabled
  if (r.feature_id && !enabledFeatureIds.has(r.feature_id)) return false;
  return cronMatches(r.cron, currentHour, currentMinute, currentDayOfWeek);
});

if (dueReminders.length === 0) {
  return [{ json: { skip: true, reason: `No reminders due at ${currentHour}:${String(currentMinute).padStart(2,'0')} UTC` } }];
}

// Return one item per due reminder
return dueReminders.map(r => ({ json: { reminder: r, skip: false } }));

// Personalize the reminder message for this user
const user = $json;
const reminder = $('Per Reminder').item.json.reminder;

let message = reminder.message || '';

// Substitute user-specific tokens
message = message
  .replace(/{name}/g, user.first_name || 'there')
  .replace(/{daily_calorie_target}/g, user.daily_calorie_target || 2000);

return [{ json: {
  telegramId: user.telegram_id,
  message,
  reminderId: reminder.id,
  reminderType: reminder.type
} }];
